#!/usr/bin/env python3
"""Convert prompt-history.jsonl to simplified format."""

import json
import sys
from datetime import datetime


def parse_timestamp(timestamp):
    """Convert timestamp to Unix milliseconds."""
    if isinstance(timestamp, (int, float)):
        return int(timestamp)
    # ISO 8601 string
    dt = datetime.fromisoformat(timestamp.replace("Z", "+00:00"))
    return int(dt.timestamp() * 1000)


def convert_prompt_entry(entry):
    """Convert a single prompt history entry to format 2."""
    return {
        "timestamp": parse_timestamp(entry["timestamp"]),
        "cwd": entry["cwd"],
        "prompt": entry["prompt"],
    }


def convert_prompt_stream(input_stream, output_stream):
    """Convert prompt-history entries from input stream to output stream."""
    for line in input_stream:
        line = line.strip()
        if not line:
            continue
        entry = json.loads(line)
        converted = convert_prompt_entry(entry)
        output_stream.write(json.dumps(converted) + "\n")


def main():
    if len(sys.argv) == 1:
        # Stream mode: read from stdin, write to stdout
        convert_prompt_stream(sys.stdin, sys.stdout)
    elif len(sys.argv) == 3:
        # File mode: read from file, write to file
        input_file = sys.argv[1]
        output_file = sys.argv[2]
        with open(input_file) as f_in, open(output_file, "w") as f_out:
            convert_prompt_stream(f_in, f_out)
        print(f"Converted {input_file} -> {output_file}", file=sys.stderr)
    else:
        print(f"Usage: {sys.argv[0]} [<input_file> <output_file>]", file=sys.stderr)
        print(f"  No args: read from stdin, write to stdout", file=sys.stderr)
        print(f"  Two args: convert input_file to output_file", file=sys.stderr)
        sys.exit(1)

