        return int(timestamp)
    # ISO 8601 string
    dt = datetime.fromisoformat(timestamp.replace("Z", "+00:00"))
    return int(dt.timestamp() * 1000)


def filter_args(
    args, allowed_fields={"command", "pattern", "path", "filePath", "query", "intent"}
):
    """Filter args to only include specified fields."""
    if not isinstance(args, dict):
        return {}
    return {k: v for k, v in args.items() if k in allowed_fields}


def convert_tool_entry(entry):
    """Convert a single tool entry to simplified format."""
    # Extract tool name (handle both formats)
    tool_name = entry.get("tool_name") or entry.get("toolName")

